"""
MKT Context Commentary — Jeremiah chapters 7–9
Run: python3 scripts/zc-context-jeremiah-7-9-fill.py

Source data used:
- data/interlinear/jeremiah.json
- data/translation/draft/mediating/jeremiah.json

Key decisions in this range:
- Ch 7 Temple Sermon treated as addressed to Josiah-era pilgrims using the temple as
  a magical talisman; the triple-repetition formula (v. 4) is treated as a covenant-
  security mantra the sermon targets, not as liturgy
- The Shiloh precedent (vv. 12-15) is the historical argument for temple vulnerability;
  Shiloh's destruction by the Philistines (1 Sam 4) is the only case in the OT of YHWH
  abandoning an established sanctuary
- Ch 7:21-23 sacrifice-critique treated as a prioritization argument (obedience > ritual),
  not an anti-sacrifice polemic; 'I did not speak about burnt offerings' targets the
  distorted use of sacrifice as covenant substitute, not the sacrificial system itself
- Ch 8:8 'lying pen of the scribes' treated as scribal interpretive distortion, not
  forgery; the scribes claimed Torah approval for practices it condemned
- Ch 9:4 'every brother is a Jacob' treated as deliberate wordplay on the patriarch's
  name (heel-grabber/deceiver: Gen 27:36)
- Ch 9:23-24 treated as one of the most programmatic prophetic-wisdom summaries;
  Paul's 1 Cor 1:31 and 2 Cor 10:17 quotations noted
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JER = {
  "7": {
    "1": "<p>'This is the word that came to Jeremiah from the LORD' — the Temple Sermon (7:1-15) is one of Jeremiah's most famous discourses. A parallel and shorter version appears in chapter 26, where the historical setting (the beginning of Jehoiakim's reign, 609 BCE) and the social consequences (attempted execution of Jeremiah) are described. The sermon was delivered at the North Gate or the Benjamin Gate of the temple courts — a high-traffic entry point where pilgrims arrived for festival worship. Chapter 26:10 specifies that the officials and priests gathered to try Jeremiah for speaking the sermon.</p>",
    "2": "<p>'Stand at the gate of the LORD's house and proclaim this word there' — the temple gate as the preaching location was maximally provocative: Jeremiah addressed the worshippers at the moment of their entry into the sacred space. The gate was also the standard judicial venue (Ruth 4:1; Deut 21:19) — Jeremiah's sermon functions simultaneously as worship challenge and legal indictment. The audience is 'all you of Judah who come through these gates to worship the LORD' — the festival pilgrimage crowd who had come believing that temple attendance guaranteed covenant security.</p>",
    "3": "<p>'Reform your ways and your actions, and I will let you live in this place' — the conditional promise: the land tenure is not automatic but dependent on covenant behavior. 'This place' (<em>hammāqôm hazzeh</em>) refers to Jerusalem and the land, not the temple specifically — the whole land is under conditional tenure. The sequence 'reform your ways and your actions' uses two related Hebrew terms (<em>darkĕkem</em> = paths/lifestyle; <em>maʿalĕlêkem</em> = deeds/practices) to cover the full scope of behavior — both habits and specific acts. The covenant promise of dwelling in the land is not irrevocable.</p>",
    "4": "<p>'Do not trust in these deceptive words: The temple of the LORD, the temple of the LORD, the temple of the LORD!' — the triple repetition was either a liturgical formula or a talismanic chant used by pilgrims as a covenant-security guarantee. The belief that YHWH's presence in the temple made Jerusalem inviolable had theological grounding in the Zion theology of the Psalms (Ps 46:5: 'God is within her, she will not fall') and in the miraculous defeat of Sennacherib in 701 BCE (2 Kings 19:35-36). Jeremiah attacks the misapplication of this theology as a substitute for covenant obedience — the temple presence does not override the covenant conditions.</p>",
    "5": "<p>'For if you truly reform your ways and your actions, if you truly administer justice between one person and another' — the double <em>ʾim-hêṭēb tēyṭîbû</em> (truly do well / truly make good) uses the emphatic infinitive absolute + finite verb construction for moral seriousness: this is not a minimal-standard condition but a genuine transformation standard. 'Administer justice between one person and another' (<em>bên ʾîš ûbên rēʿēhû</em>) targets the judicial corruption that Amos, Micah, and Isaiah also condemned: the partiality toward the powerful and against the powerless in the city-gate court system.</p>",
    "6": "<p>'If you do not exploit the foreigner, the fatherless, or the widow, or shed innocent blood in this place' — the triad of vulnerable people (foreigner, fatherless, widow) appears throughout Deuteronomy (10:18; 14:29; 24:17-21; 27:19) and the prophets as the test of covenant justice. 'Shed innocent blood in this place' most likely refers to judicial murders (cf. 26:15: Jeremiah warns them not to shed innocent blood by executing him) — miscarriages of justice that produced death sentences on the innocent. The temple courts were themselves the scene of political violence against true prophets.</p>",
    "7": "<p>'Then I will let you live in this place, in the land I gave your ancestors for ever and ever' — the <em>lĕʿôlam wāʿed</em> (forever and ever) tenure in the land is the conditional covenant promise: it is available in perpetuity, but only while the conditions are met. The contrast with the current situation — where the conditions are not met and therefore the promise is suspended — is the argumentative point. The exile will not be permanent punishment of a people who theoretically deserve the land; rather, the land tenure itself is covenantally dependent on the behavior described in vv. 5-6.</p>",
    "8": "<p>'But look — you are trusting in deceptive words that can do you no good' — <em>dibrê haššeqer</em> (words of falsehood/deception) is the same phrase applied to false prophecy throughout Jeremiah (14:14; 23:25,32; 27:10,14,16; 29:9,21). The temple-formula of v. 4 belongs in the same category as false prophetic assurance: it promises peace and security that the covenant conditions have not established. 'That can do you no good' (<em>ʾăšer lōʾ yôʾîlû</em>) — the worthless-idol formula also applied to other gods (2:11; 16:19) — classifies trust in the temple-formula as equivalent to trust in idols.</p>",
    "9": "<p>'You steal, murder, commit adultery, swear falsely, sacrifice to Baal, and follow other gods you have never known' — the Decalogue violations are listed in condensed form: theft (8th commandment), murder (6th), adultery (7th), false swearing (probably 9th: bearing false witness), Baal sacrifice and other gods (1st and 2nd). The deliberate Decalogue echo makes the point that temple attendance is being used to neutralize the very covenant obligations that temple worship was supposed to reinforce. The worshippers are not ignorant pagans but covenant people violating their own explicit commitments.</p>",
    "10": "<p>'And then come and stand before me in this house that bears my name, and say, We are safe!' — <em>niṣṣalnû</em> (we are delivered/safe) is the legal term for acquittal — the people treat temple attendance as a legal discharge from covenant liability. The 'house that bears my name' (<em>ʿal-bêt ʾăšer niqrāʾ-šĕmî ʿālāyw</em>, the house over which my name has been called) is the standard designation for the Jerusalem temple — the name-bearing is the basis of the false confidence. To have YHWH's name called over a place was to mark it as YHWH's territory and therefore safe; Jeremiah attacks the magical interpretation of this territorial designation.</p>",
    "11": "<p>'Has this house, which bears my name, become a den of robbers in your eyes? I myself have seen it!' — the 'den of robbers' (<em>mĕʿārat pārîṣîm</em>) is not a place where robbery is committed but a place where robbers feel safe to take refuge after committing crimes elsewhere. The image is of criminals who return to their hideout to rest between raids — the temple has become the place where covenant violators retreat after their sins, confident in ritual protection. Jesus quotes this passage directly at the temple cleansing (Mark 11:17; Matt 21:13; Luke 19:46), applying it to the commercial practices that had turned the courts of the house into an exploitative marketplace.</p>",
    "12": "<p>'Go now to my place that was in Shiloh, where I first caused my name to dwell, and see what I did to it' — the Shiloh precedent is the historical argument for temple vulnerability. Shiloh in Ephraim (modern Khirbet Seilun) was the site of the tabernacle after the conquest (Josh 18:1) and the location of the ark during the period of the judges. Eli and Samuel ministered there (1 Sam 1-3). YHWH allowed the Philistines to capture the ark and destroy Shiloh (1 Sam 4:10-11; Ps 78:60-64) when Israel treated it as a magical battle-talisman. Archaeological excavations at Shiloh confirm a destruction layer from the late eleventh century BCE consistent with the biblical account.</p>",
    "13": "<p>'And now, since you have done all these things ... and though I spoke to you again and again you did not listen' — the phrase 'spoke to you again and again' (<em>dabbēr ʾēlêkem haškēm wĕdabbēr</em>, rising early to speak) appears repeatedly in Jeremiah (7:25; 11:7; 25:3-4; 26:5; 29:19; 32:33; 35:14-15; 44:4) and is one of his characteristic descriptions of the prophetic tradition's persistent and unheeded warnings. The image of YHWH rising early to send his prophets anthropomorphizes divine urgency — the same urgency that Israel repeatedly rejected with silence and stubbornness.</p>",
    "14": "<p>'Therefore I will do to this house that bears my name, and in which you trust, and to this place that I gave to you and your ancestors, exactly as I did to Shiloh' — the destruction of the Jerusalem temple is predicted in the same terms as the destruction of Shiloh. The prediction was radical: for Jeremiah's contemporaries, trained in Zion theology, the temple's destruction was as theologically impossible as the repeal of the creation order. This is the sermon that led to the attempted execution of Jeremiah (26:7-11), because it was heard as the blasphemy of declaring YHWH's chosen dwelling place expendable.</p>",
    "15": "<p>'And I will drive you out of my presence, just as I drove out all your kinsmen — the entire offspring of Ephraim' — the driving-out from the divine presence is the language of exile and covenant exclusion: the same formula used for Adam and Eve's expulsion from Eden (Gen 3:23-24). 'The entire offspring of Ephraim' is the Northern Kingdom, exiled by Assyria in 722-720 BCE. Jeremiah presents Judah not as YHWH's guaranteed remnant but as the southern twin of the exiled north — equally capable of forfeiting the covenant relationship through the same pattern of behavior.</p>",
    "16": "<p>'As for you, do not pray for this people, do not lift up a cry or prayer on their behalf, and do not press me with intercession — for I will not listen to you' — the prohibition of intercessory prayer for Israel is one of Jeremiah's most theologically startling passages (cf. 11:14; 14:11-12). Moses's greatest moments of covenant faithfulness were his intercessory prayers (Exod 32:11-14; Num 14:13-19); YHWH's refusal to hear even Jeremiah's intercession signals that the covenant has reached a terminal judgment point. The prophet who has been commanded not to pray experiences the same covenant silence as his people.</p>",
    "17": "<p>'Do you not see what they are doing in the towns of Judah and in the streets of Jerusalem?' — the rhetorical question invites YHWH's observation (or the audience's awareness) of the public worship of the queen of heaven described in v. 18. The idolatry is not hidden cult practice but performed openly in the streets and public squares of the capital city. The civic character of the apostasy — the entire family unit participating, the public streets serving as ritual space — makes individual dissociation impossible.</p>",
    "18": "<p>'The children gather wood, the fathers light the fire, and the women knead the dough to make cakes for the queen of heaven' — the queen of heaven (<em>mĕleket haššāmāyim</em>) was probably Astarte/Ishtar, the Mesopotamian goddess of love and war, or possibly the Canaanite Asherah. Her worship involved star-shaped cakes (<em>kĕwānîm</em>, probably a borrowed Akkadian word for a specific shaped bread offering). Jeremiah 44:15-19 shows that this cult was primarily maintained by women who credited the queen of heaven with the prosperity of Josiah's era and blamed its abandonment under Josiah's reform for Judah's subsequent decline. The family-unit participation (children, fathers, women) describes a household religious practice.</p>",
    "19": "<p>'But is it really me they are provoking? declares the LORD. Is it not themselves they are provoking, bringing shame on themselves?' — the rhetorical shift from divine anger to divine indifference is stark: YHWH is not psychologically threatened by the queen of heaven cult; the people are harming themselves, not YHWH. The harm is double: the loss of divine protection (the actual source of security) and the inevitable shame of discovered apostasy. The same argument appears in Deuteronomy 32:21 (the provocation-theme) and Paul's use of the text in Romans 10:19.</p>",
    "20": "<p>'My anger and my wrath are about to be poured out on this place — on human and animal, on the trees of the field and the crops of the ground — and it will burn and will not be quenched' — the unquenchable wrath (<em>wĕbāʿărāh wĕlōʾ tikhbeh</em>) applied to the entire agricultural ecosystem reflects the Deuteronomic curse pattern: covenant violation brings devastation that is comprehensive and not easily reversed (Deut 28:20-24: disease, drought, defeat). The comprehensive scope (human, animal, vegetation) recalls the Exodus plagues, which also attacked Egypt's entire ecosystem. The burning that 'will not be quenched' anticipates the fall of Jerusalem and the fires of 587/586 BCE.</p>",
    "21": "<p>'Go ahead — add your burnt offerings to your other sacrifices and eat the meat yourselves' — the permission is ironic: if sacrifice has been reduced to a ritual performance detached from covenant obedience, YHWH will not participate in it. The burnt offering (<em>ʿōlāh</em>) was entirely consumed by fire; the fellowship/peace offering (<em>zĕbāḥ</em>) was shared between God and the offerers. By permitting them to consume the burnt offering themselves, YHWH is withdrawing his presence from the transaction — the sacrifice continues but YHWH is not party to it.</p>",
    "22": "<p>'For on the day I brought your ancestors out of Egypt, I did not speak with them or give them commands about burnt offerings and sacrifices' — this is not a historical denial that sacrifice was commanded at Sinai (it clearly was: Exod 20:24; 24:5; Lev 1-7) but a prioritization argument. The fundamental Sinai covenant was 'Obey me, and I will be your God' (v. 23) — the relational commitment preceded and grounded the ritual system. Sacrifice was instituted as the expression of the covenant relationship, not as its substitute. The same logic is found in 1 Samuel 15:22 (Saul), Amos 5:21-24, Hosea 6:6 (quoted by Jesus twice: Matt 9:13; 12:7), and Micah 6:6-8.</p>",
    "23": "<p>'Rather, I gave them this command: Obey me, and I will be your God, and you will be my people' — the covenant formula in its most concise form: mutual possession through obedience. 'I will be your God and you will be my people' (<em>ʾănî ʾĕlōhêkem wĕʾattem ʿammî</em>) is the canonical covenant summary that runs from Exodus through Jeremiah (31:33) into Ezekiel (36:28) and Revelation (21:3). 'Walk in all the ways I command you, so that it may go well with you' — the walk-in-ways formula is Deuteronomy's constant idiom for covenant lifestyle: comprehensive obedience oriented toward the covenant blessing.</p>",
    "24": "<p>'But they did not listen or pay attention; they followed their own plans, the stubbornness of their evil hearts' — <em>šĕrîrût libbām hārāʿ</em> (the stubbornness of their evil hearts) is one of Jeremiah's characteristic diagnoses (3:17; 9:14; 11:8; 13:10; 16:12; 18:12; 23:17). The heart's stubbornness is an internal disposition that resists external instruction — it is the condition that makes covenant obedience structurally impossible without the heart-transformation promised in 31:33 and Ezekiel 36:26-27. 'They turned their backs and went backward, not forward' is the spatial image for moral regression: the covenant journey requires forward movement toward YHWH; Israel is moving in the opposite direction.</p>",
    "25": "<p>'From the day your ancestors came out of Egypt until this very day, I have persistently sent all my servants the prophets' — the 'rising early to send the prophets' formula covers the entire period of Israel's national existence. The prophetic tradition from Moses through Elijah, Amos, Hosea, Isaiah, and Micah represents YHWH's patient, persistent communication before judgment. The 'servants the prophets' (<em>ʿăbādāyw hanĕbîʾîm</em>) formula appears in the DH (2 Kings 9:7; 17:13,23; 21:10; 24:2) as the standard description of the prophets' role — they are covenant intermediaries whose warnings define the justice of the judgment that follows.</p>",
    "26": "<p>'Yet they did not listen to me or pay attention; they were stubborn and stiff-necked. They behaved even worse than their ancestors' — <em>qāšû ʾet-ʿorpām</em> (they hardened their neck) is the standard OT idiom for covenant resistance (Exod 32:9; 33:3,5; Deut 9:6,13; 31:27; 2 Kings 17:14; Neh 9:16,17,29). The intensification — 'they behaved even worse than their ancestors' — places Jeremiah's generation at the bottom of the covenant-faithfulness decline curve. The DH (2 Kings 17:7-23) uses the same analysis for the Northern Kingdom's fall; Jeremiah applies it to Judah.</p>",
    "27": "<p>'You will speak all these words to them, but they will not listen. You will call to them, but they will not respond' — the prophetic commission is given against the explicit prediction of its failure. This is the 'hardening' dynamic that appears in Isaiah's call (Isa 6:9-10: 'Hear, but do not understand; see, but do not perceive'). The prophet is not given a mission that will succeed if he does his part well; he is given a mission whose immediate outcome is already determined. The purpose of prophetic speech that will not be heard is to create the record of prior warning that grounds the justice of the judgment.</p>",
    "28": "<p>'This is the nation that did not obey the LORD their God and refused to accept correction' — the summary indictment: failure to obey + refusal of correction (<em>mûsār</em>). The <em>mûsār</em> terminology (discipline, correction, chastisement) is wisdom vocabulary: a person who refuses <em>mûsār</em> in Proverbs is the fool who cannot be taught (Prov 1:7; 5:12; 12:1). Israel has become the foolish nation — not ignorant of the covenant but willfully resistant to its corrective mechanisms. 'Truth has vanished; it has disappeared from their lips' — <em>ʾĕmuwnāh</em> (faithfulness/truth) is the covenant-loyalty term: the community's speech no longer reflects the covenant reality.</p>",
    "29": "<p>'Shave off your hair and throw it away; raise a dirge on the hilltops, for the LORD has rejected and abandoned this generation under his wrath' — the shaving of hair was a standard ANE mourning rite (Job 1:20; Ezek 27:31) associated with death and disaster. The command to raise a dirge (<em>qînāh</em>) on the hilltops — the same locations used for Baal worship — converts the cultic high places into sites of national lamentation. 'The LORD has rejected and abandoned this generation' (<em>zānab Yhwh ûyyiṭōš ʾet-dôr ʿebrātô</em>) is covenant-abandonment language: the generation has reached the end of YHWH's patience.</p>",
    "30": "<p>'For the people of Judah have done evil in my sight, declares the LORD; they have installed their detestable idols in the house that bears my name, defiling it' — the temple-defilement charge is historically specific: Manasseh installed Asherah poles, altars for the host of heaven, and foreign cult objects in the temple courts (2 Kings 21:3-7). Josiah removed them (2 Kings 23:4-12), but the people's hearts had not changed with the reform. The defilement of the sanctuary is the most extreme form of covenant violation — attacking the holy space itself rather than merely violating covenant ethics in the secular sphere.</p>",
    "31": "<p>'They have built the shrines of Topheth in the Valley of Ben Hinnom to burn their sons and daughters in the fire — something I never commanded, and something that never even entered my mind' — the Topheth (<em>tōpet</em>, possibly meaning fireplace/hearth) was the cultic installation in the Valley of Ben Hinnom (Gehenna) south of Jerusalem where child sacrifice to Molech was practiced (2 Kings 23:10; Isa 30:33). The practice may have been Phoenician in origin, brought to Judah through the influence of Phoenician-Sidonian culture during Ahab's era (the marriage to Jezebel) and revived under Manasseh. The fire-sacrifice of children is labeled as something YHWH never commanded and never imagined — the strongest possible statement that the practice is not a legitimate expression of covenant worship.</p>",
    "32": "<p>'Therefore, the days are coming ... when this place will no longer be called Topheth or the Valley of Ben Hinnom, but the Valley of Slaughter' — the renaming is a judgment oracle: the place of intentional child-burning will become the place of mass unintentional death. 'For they will bury the dead in Topheth until there is no room left' — the irony inverts the geography of horror: the valley where Israel burned children will become the valley where Israel buries war dead. The Valley of Ben Hinnom (Gehenna) later became Jerusalem's refuse dump, burning perpetually, and the word <em>Gehenna</em> (from the Greek transliteration of <em>gēʾ hinnōm</em>) became the NT's standard term for the place of final judgment (Matt 5:22,29; 10:28; 18:9).</p>",
    "33": "<p>'The corpses of this people will become food for the birds of the sky and the wild animals of the earth, and no one will drive them away' — the unburied body is the ultimate disgrace in the ANE: proper burial was the final act of family and community obligation, and denial of burial was a curse reserved for enemies (1 Kings 21:24; 2 Kings 9:10). The 'no one to drive them away' detail is the absence of all social function: there are no surviving family members to protect the bodies, no community to maintain the minimum of human dignity in death.</p>",
    "34": "<p>'I will bring to an end the sounds of joy and gladness, the voices of the bridegroom and the bride, in the cities of Judah and the streets of Jerusalem — for the land will become a wasteland' — the stopping of wedding sounds is the quintessential image of social death in the ancient world: marriage, procreation, and social celebration are the most basic human activities that continue even in adverse conditions. When weddings stop, the community has ceased to function. Jeremiah uses this image at 16:9 and 25:10; Revelation 18:23 applies the same image to the fall of Babylon. The 'voice of the bridegroom and bride' appears positively in 33:11 as a sign of restoration.</p>",
  },
  "8": {
    "1": "<p>'At that time ... the bones of the kings of Judah, the bones of its officials, the bones of the priests, the bones of the prophets, and the bones of Jerusalem's inhabitants will be brought out of their graves' — the desecration of the royal tombs is one of the most extreme forms of posthumous judgment imaginable in the ANE. Kings were buried with honor in dynastic tombs (the tombs of David: 1 Kings 2:10); disruption of royal burials was practiced by invaders as a sign of complete domination. The specific categories — kings, officials, priests, prophets, inhabitants — correspond exactly to the leadership classes indicted in 2:8 and 7:26. The judgment is comprehensive across all social strata.</p>",
    "2": "<p>'They will be exposed before the sun, the moon, and all the host of heaven — which this people loved, served, followed, consulted, and worshipped' — the five-verb indictment for astral worship is the most concentrated description of star-cult devotion in the OT. The five verbs (loved, served, followed, consulted, worshipped) describe different aspects of the relationship with astral deities: emotional attachment (<em>ʾāhab</em>), active service (<em>ʿābad</em>), lifestyle orientation (<em>hālak ʾaḥărê</em>), inquiry (<em>dāraš</em>), and prostration (<em>šāḥāh</em>). The ironic punishment is that the bones will be exposed before the very celestial objects the people worshipped — but now as refuse, not as devotees.</p>",
    "3": "<p>'And all the survivors of this evil family who remain in all the places where I have driven them will prefer death to life' — the desire for death over life reverses the life-orientation of the covenant: YHWH offered 'life and prosperity' (Deut 30:15), and the covenant people are now choosing their opposites. The survivors in the diaspora will have witnessed such devastation that continued existence offers nothing — the annihilation of their entire social world (temple, land, community, institutions) makes death preferable to the meaningless survival of a covenant people without their covenant context.</p>",
    "4": "<p>'When people fall, don't they get back up? When someone turns away, don't they come back?' — the wisdom sayings contrast natural human resilience with Israel's theological stubbornness. When a person stumbles (<em>yippōl</em>), they naturally rise (<em>yāqûm</em>); when they turn away (<em>yāšûb</em>), they naturally return (<em>yāšûb</em>). The wordplay is intentional: the 'returning' that characterizes normal human behavior is precisely what Israel refuses to do in its covenant context. Repentance (<em>šûbāh</em>) is treated as less demanding than the automatic physical response to falling — and yet Israel will not do it.</p>",
    "5": "<p>'Then why has this people — Jerusalem — turned away in perpetual backsliding? They cling to deception and refuse to come back' — <em>mĕšûbāh niṣṣaḥat</em> (perpetual/eternal backsliding) is Jeremiah's diagnostic: the turning away has become a permanent orientation rather than a temporary failure. 'Clinging to deception' (<em>heḥĕzîqû bammirmāh</em>) uses the same verb <em>ḥāzaq</em> (to hold fast/cling) used for Israel's covenant loyalty to YHWH in positive contexts (Deut 10:20; Ruth 1:14) — the irony is that the clinging-loyalty that should be directed toward YHWH is now directed toward the deceptions that substitute for him.</p>",
    "6": "<p>'No one repents of his wickedness and asks, What have I done?' — the absence of the diagnostic question 'What have I done?' is the sign of moral self-awareness destroyed. The horse-plunging-into-battle image is vivid: warhorses trained for cavalry combat charge without deliberation, driven by training and adrenaline. Israel's moral behavior has become similarly automatic and unreflective — each person charges ahead on their own course (<em>šāqap bĕmĕrûṣātô</em>) without pausing to assess direction or destination. The absence of moral deliberation is itself a form of moral pathology.</p>",
    "7": "<p>'Even the stork in the sky knows when to migrate; the turtledove, the swallow, and the crane observe the season of their return — but my people do not know the requirements of the LORD' — the migratory bird comparison is a form of shame rhetoric: the birds follow their divinely-embedded instincts with precision; Israel ignores its divinely-given covenant. The four birds listed were familiar to the Levantine climate as seasonal migrants. <em>Mišpāṭ Yhwh</em> (the requirements/ordinances of the LORD) refers to the covenant norms that the Torah made explicit — Israel's failure is not lack of information but lack of attentiveness to what the birds instinctively know: the right season for the right response.</p>",
    "8": "<p>'How can you claim, We are wise, and we have the law of the LORD? But in fact the lying pen of the scribes has turned it into a lie' — the 'lying pen of the scribes' (<em>ʿēṭ šeqer sōpĕrîm</em>) is a critique of the scribal interpretation tradition that was producing Torah commentary and legal rulings in Jeremiah's era. Whether this refers to literal forgery (scholars debate) or to interpretive distortion that created legal loopholes from Torah requirements, the indictment is that the written law (<em>tôrat Yhwh</em>) was being undermined by the very specialists who claimed to preserve and transmit it. The critique anticipates Jesus's conflicts with scribal tradition (Matt 15:6: 'you have made void the word of God by your tradition').</p>",
    "9": "<p>'The wise will be disgraced; they will be terrified and caught. They have rejected the word of the LORD — so what wisdom is left in them?' — the <em>ḥăkāmîm</em> (wise men/sages) were a distinct professional class in ancient Israel, distinct from the priests and prophets (cf. Jer 18:18: 'the law shall not perish from the priest, nor counsel from the wise, nor the word from the prophet'). Wisdom in the OT begins with the fear of the LORD (Prov 1:7); those who reject the LORD's word have destroyed the foundation of the very wisdom they claim. The categorical question 'what wisdom is left in them?' rhetorically answers itself: none.</p>",
    "10": "<p>'Therefore I will give their wives to other men and their fields to new owners, because from the least to the greatest all are consumed by greed; from prophet to priest, all deal dishonestly' — the loss of wives and fields represents the total dispossession of the household unit — the fundamental social structure of Israelite life. The universal greedy indictment (<em>miqqāṭōn wĕʿad-gādôl kullō bōṣēaʿ bāṣaʿ</em>) from least to greatest covers the entire social spectrum. The prophet-to-priest inclusion of religious leaders in the indictment mirrors the comprehensive leadership failure in 2:8 and 5:31.</p>",
    "11": "<p>'They dress the wound of my people as though it were minor, saying, Peace, peace, when there is no peace' — the 'peace, peace' (<em>šālôm šālôm</em>) false promise is one of the most memorable phrases in Jeremiah, repeated at 6:14 and echoed throughout the book's conflict with false prophets. <em>Šālôm</em> as covenant completeness — the comprehensive well-being that YHWH promises to the obedient community — has been misappropriated as a political-religious slogan assuring Jerusalem that no judgment is coming. The wound metaphor (<em>šeber</em>, the fracture/break of my people) suggests a structural injury; the false prophets are applying ointment to what requires surgery.</p>",
    "12": "<p>'Were they ashamed when they committed these detestable acts? No, they felt no shame at all; they did not even know how to blush' — the incapacity for shame (<em>hikkālēm lōʾ yēdāʿû</em>) is Jeremiah's diagnosis of the social-psychological consequence of long-established sin: the moral feedback mechanism (blushing as the involuntary sign of conscience) has been destroyed by habituation to wrong. The parallel at 6:15 connects this shame-incapacity to the confident leadership of prophets and priests who will fall in the time of punishment.</p>",
    "13": "<p>'I will take away their harvest, declares the LORD: no grapes on the vine, no figs on the fig tree, even the leaves will wither' — the agricultural curse of stripped vines and barren fig trees reverses the covenant blessing symbols. The vine and fig tree together represent the standard ANE image of peaceful agricultural plenty (1 Kings 4:25; Mic 4:4; Zech 3:10); their barrenness is the visible sign of covenant-curse. 'What I gave them will be stripped away' (<em>wāʾettēn lāhem yaʿabĕrûm</em>, lit. 'those I gave to them will pass away') — the gifts of the land return to YHWH when the land-lease conditions are violated.</p>",
    "14": "<p>'Why are we sitting here? Come, let us flee to the fortified cities and die there — for the LORD our God has condemned us and has given us poisoned water to drink, because we have sinned against the LORD' — the community voice of defeat anticipates the siege of Jerusalem. The 'sitting here' implies paralysis in the face of advancing Babylonian forces; the flight to fortified cities is the desperate last resort. 'Condemned us' (<em>hĕdimmānû</em>) and 'poisoned water' (<em>mê rōʾš</em>, water of gall/poison) are the language of the covenant curse enacted — the people recognize that their suffering is covenantally deserved, a recognition that does not produce repentance but only fatalistic acceptance.</p>",
    "15": "<p>'We hoped for peace, but no good has come; we waited for a time of healing, but instead there is only terror' — the reversal of the false prophets' promise: the community hoped for what the false prophets promised and received the opposite. This is the experiential confirmation of Jeremiah's charge against the 'peace, peace' slogan — the people who trusted the false prophets discover, in the moment of judgment, that the promise was empty. <em>Rĕpāʾût</em> (healing) is the covenant-restoration term; the 'time of healing' that has not come will be promised genuinely in 30:17 and 33:6.</p>",
    "16": "<p>'From Dan the snorting of their warhorses is heard; the whole land shakes at the sound of their stallions' neighing' — Dan was the northernmost Israelite city (modern Tel Dan), the first to be reached by an invasion from the north (the Babylonian route from Mesopotamia via the Fertile Crescent). The battle sounds starting from Dan function as an alarm that reaches the whole land progressively. The horse imagery for the Babylonian cavalry is vivid — war chariots and cavalry were the decisive military technology of the Neo-Babylonian army.</p>",
    "17": "<p>'For I am about to send poisonous snakes among you — vipers that cannot be charmed — and they will bite you, declares the LORD' — the snake-that-cannot-be-charmed image builds on the 'poisoned water' (<em>rōʾš</em> = poison/gall) theme of v. 14. Snake-charming was a recognized practice in the ancient Near East (cf. Ps 58:4-5; Eccl 10:11); the vipers that resist charming are invaders whose advance cannot be neutralized by any means — neither diplomatic negotiation nor magical protection. The image connects to Numbers 21:6 (YHWH sending fiery serpents against Israel in the wilderness) — the same divine agent who once used serpents to discipline Israel uses them again.</p>",
    "18": "<p>'My sorrow is beyond healing; my heart is faint within me' — the shift from divine oracle to prophetic lament is sudden and significant. Jeremiah speaks in his own voice about his personal grief over the coming judgment he has been proclaiming. The 'sorrow beyond healing' (<em>yaʾgôn ʿālay libbî dāwwāy</em>) reflects the prophet's unique position: he knows the judgment is justified and coming, but he is not emotionally detached from the people who will suffer it. Jeremiah is often described as 'the weeping prophet' because of passages like this, 9:1, and the Lamentations attributed to him.</p>",
    "19": "<p>'Listen — the cry of my people from a distant land: Is the LORD not in Zion? Is her King no longer there?' — the distant-land cry is the voice of exile before it has happened: Jeremiah hears in prophetic vision the anguished questions of a dispersed people asking whether the exile has voided the Zion covenant. 'Is her King no longer there?' — <em>ʾên malkāh bāh</em> — directly challenges the Davidic kingship theology. YHWH's inserted counter-question ('Why have they provoked me with their carved idols and worthless foreign gods?') answers the cry with the reason for the divine absence: idolatry caused the very abandonment the people now lament.</p>",
    "20": "<p>'The harvest is over, the summer has ended — and we are still not saved' — this is among the most poignant lines in Jeremiah: the agricultural seasons have passed, the opportunities for action have run out, and salvation has not come. In Palestinian agriculture, the grain harvest (spring) and the summer fruit harvest (August-September) together constituted the year's productive capacity; when both were over, the year was finished. The seasonal metaphor expresses a theological reality: the time for repentance and covenant restoration has closed, and the people are still in their unresolved crisis. Paul may have this image in mind with 'now is the acceptable time' (2 Cor 6:2).</p>",
    "21": "<p>'I am broken over the brokenness of my people; I mourn, and horror has gripped me' — <em>ʿal-šeber bat-ʿammî hušbārtî</em> (I am broken over the breaking of my people's daughter) — Jeremiah participates in the very judgment he has announced. The word <em>šeber</em> (breaking, fracture) is used for the mortal wound that will bring Judah down; Jeremiah suffers that wound vicariously. This is not professional detachment but pastoral solidarity: the prophet's grief is proportionate to the scale of the disaster. Lamentations 2:11 uses similar language in Jeremiah's voice over the fall of Jerusalem.</p>",
    "22": "<p>'Is there no balm in Gilead? Is there no physician there? Then why has the wound of my people not been healed?' — Gilead (Transjordan) was famous in antiquity for its balsam resin (<em>ṣĕrî</em>), used as a wound-dressing and healing agent (Gen 37:25: Joseph sold by the Midianites who were carrying Gileadite balm to Egypt). The three rhetorical questions are saturated with grief: the resources exist (balm, physician), yet the healing has not come. The answer — implied but not stated — is that Israel's wound is not physical but covenantal, and the covenantal physician is being refused. The image inspired the American spiritual 'There Is a Balm in Gilead,' which applies the image christologically: the healing that is not available through the law is available through the gospel.</p>",
  },
  "9": {
    "1": "<p>'Oh that my head were a spring of water and my eyes a fountain of tears, so that I could weep day and night for the slain of my dear people!' — the opening wish for supernatural capacity for grief establishes chapter 9 as the fullest expression of Jeremiah's prophetic sorrow. 'My dear people' (<em>bat-ʿammî</em>, daughter of my people) is an affectionate collective term for the community. The 'slain' (<em>ḥalalê</em>) are those killed in battle and by the siege — not yet historical events at the time of writing but prophetically certain. Jeremiah's tears are the human emotional counterpart to the divine grief that drives the judgment.</p>",
    "2": "<p>'Oh that I had a lodging place for travelers in the wilderness, so that I could leave my people and go away from them!' — the wish for escape from his own people is the darkest expression of prophetic isolation. The contrast between vv. 1-2 is striking: in v. 1 Jeremiah wishes he could weep more for them; in v. 2 he wishes he could flee from them. Both impulses are authentic: deep grief and deep revulsion coexist in the prophet's experience of a people he loves but who are 'all adulterers' (<em>kî kullām mĕʾănāpîm</em>) and 'a gathering of traitors' (<em>ʿăṣeret bōgĕdîm</em>). The tension between prophetic compassion and prophetic honesty is never resolved in Jeremiah.</p>",
    "3": "<p>'They have bent their tongue like a bow to shoot falsehood; they have grown powerful in the land but not by truth' — the tongue-as-bow metaphor pictures deliberate deception as an aggressive act: lies are arrows aimed at specific targets. The 'growing powerful not by truth' (<em>lōʾ lĕʾĕmûnāh gāberû bāʾāreṣ</em>) describes the social-political success that the faithless have achieved — their prosperity proves not that their behavior is acceptable but that the covenant consequences have been temporarily deferred. 'They do not know me, declares the LORD' — <em>yādaʿ</em> in the covenant-intimacy sense: their practical behavior demonstrates the absence of genuine relationship, regardless of their religious vocabulary.</p>",
    "4": "<p>'Beware of your neighbors; put no trust in any relative — for every brother is a schemer, and every neighbor goes around spreading slander' — the 'every brother is a Jacob' idiom: <em>kol-ʾāḥ ʿāqôb yĕʿāqēb</em> (every brother is a deceiver/Jacob). The verb <em>ʿāqab</em> means to supplant/trip up from behind; it is the root of the name Jacob (<em>yaʿăqōb</em>), who supplanted Esau (Gen 25:26; 27:36: 'Is he not rightly named Jacob? He has supplanted me twice!'). Jeremiah's society has generalized the Jacob-trait: the competitive deception that characterized the patriarch's early life has become the universal social norm. The betrayal of family and neighbor destroyed the social trust that covenant community required.</p>",
    "5": "<p>'Everyone deceives his neighbor, and no one tells the truth. They have trained their tongue to lie; they exhaust themselves committing sin' — <em>limmĕdû lĕšônām dabbēr-šeqer</em> (they have trained their tongue to speak falsehood) treats deception as an acquired skill: the ability to lie fluently requires practice and habituation. The exhaustion through sin (<em>nileʾû ʿăwōtām</em>) is the moral version of the physical exhaustion of pointless labor — sustained transgression that produces no genuine benefit and drains the transgressor. The spiritual-agricultural metaphor runs throughout the book: covenant violation is literally fruitless and tiring.</p>",
    "6": "<p>'You live in the midst of deception; through their deceit they refuse to know me, declares the LORD' — the deception has become the social environment: there is no social space outside of it. The refusal to know YHWH is described as an active choice enabled by the deception — the lies people tell create an alternative reality that crowds out the true knowledge of YHWH. In the Johannine register, this is the dynamic of darkness that 'hates the light' (John 3:20); in Jeremiah's register, it is the social construction of a lie-world that makes covenant truth inaccessible.</p>",
    "7": "<p>'Therefore this is what the LORD of hosts says: I will refine them and test them — for what else can I do with my sinful people?' — the divine query 'what else can I do?' (<em>mâ-ʾeʿĕśeh</em>) is one of the most remarkable expressions of divine perplexity in the OT. It does not indicate divine helplessness but divine faithfulness to a people who have exhausted all normal means of covenant restoration: warnings have been given, prophets have been sent, judgment has been threatened. The refining-and-testing metaphor (Prov 17:3; 27:21; Isa 48:10; Mal 3:3) describes the purifying judgment: the exile will burn away the dross, but the process is painful for the metal.</p>",
    "8": "<p>'Their tongue is a lethal arrow that shoots out deceit. With their mouths they speak peace to their neighbors, but in their hearts they are planning an ambush' — the peace-from-the-mouth / ambush-in-the-heart contrast is the prophetic diagnosis of covenant social collapse: the language of covenant solidarity (<em>šālôm</em>) is maintained while the practice of betrayal continues. This is what makes Jeremiah's era particularly dangerous: it is not openly hostile society but covertly treacherous society. The false peace-speaking is worse than open enmity because it prevents the betrayed party from protecting themselves.</p>",
    "9": "<p>'Should I not punish them for all this? declares the LORD. Should I not take vengeance on such a nation as this?' — the double rhetorical question expects 'yes' and functions as a legal declaration of just cause for judgment. The identical formulation appears at 5:9 and 5:29, creating a refrain that punctuates the judgment oracles with legal self-justification. YHWH is not acting arbitrarily or out of wounded pride but in response to specific, documented covenant violations — the judgment is proportionate and just.</p>",
    "10": "<p>'I will take up weeping and wailing for the mountains and lamentation for the wilderness pastures, for they have been laid waste so that no one passes through' — the mourning over the mountains and pastures personifies the land as a victim of the judgment, not merely its location. In the ANE, the land was understood as a moral agent responsive to the behavior of its inhabitants (Lev 18:25,28: the land vomits out its sinful inhabitants; Deut 11:17: the land refuses to yield its produce when YHWH withholds rain). The silence of the vacated land — no cattle, no birds, no wildlife — is the ecological consequence of the covenantal devastation.</p>",
    "11": "<p>'I will make Jerusalem a heap of rubble, a haunt of jackals; I will make the cities of Judah a wasteland, with no one living in them' — the jackal-haunt (<em>mĕʿôn tannîm</em>) is one of the standard prophetic images for desolated cities (Isa 13:22; 34:13; 35:7; Jer 10:22; 49:33; 51:37; Mal 1:3). Jackals are scavengers that inhabit ruins — their presence marks a human settlement as definitively abandoned. The image was fulfilled in the post-586 BCE devastation of Judah, which archaeological surveys confirm as a dramatic population collapse across multiple sites. The Lachish Letters, written just before the Babylonian final assault, reflect a Judah rapidly losing its cities.</p>",
    "12": "<p>'Who is wise enough to understand this? Who has received the word from the LORD and can explain it? Why has the land been ruined and laid waste like a desert that no one crosses?' — the wisdom-challenge is addressed to the sage class (8:8-9): the wisest interpreter of events is the one who can explain why the land has been destroyed. The question challenges the covenant-logic skeptics who attributed Judah's difficulties to political misfortune or divine indifference rather than to covenant violation. The answer in vv. 13-14 is programmatic: abandonment of the Torah + Baal-following = destruction.</p>",
    "13": "<p>'Because they have abandoned my law that I placed before them, and have not obeyed my voice or followed it' — the two-part answer: law abandonment + voice disobedience. 'My law that I placed before them' (<em>tôrātî ʾăšer nātattî lipnêhem</em>) refers specifically to the written Torah — the covenant document that Moses deposited beside the ark (Deut 31:26) and that Josiah's reform had rediscovered (2 Kings 22:8). The written law's public availability makes its abandonment inexcusable: the people had access to the covenant terms and chose to disregard them.</p>",
    "14": "<p>'Instead they followed the stubbornness of their own hearts and went after the Baals, just as their ancestors had taught them' — <em>šĕrîrût libbām</em> (the stubbornness of their hearts) appears again as Jeremiah's signature diagnosis. The generational transmission of Baal worship — 'just as their ancestors had taught them' — points to the family-based religious formation described in 7:18 (children, fathers, and women all participating in the queen of heaven cult). The apostasy is not individual but systemic: it has been embedded in the intergenerational transmission that Torah commanded for covenant faithfulness (Deut 6:7) but that has been redirected to Baal instead.</p>",
    "15": "<p>'I will feed this people with wormwood and give them poisoned water to drink' — wormwood (<em>laʾănāh</em>) was an extremely bitter plant (Artemisia absinthium, still used in absinthe); to eat it was proverbially associated with suffering and injustice (Prov 5:4; Amos 5:7; 6:12). Poisoned water (<em>mê rōʾš</em>) continues the bitter-water image from 8:14. In contrast to the 'spring of living water' that YHWH is (2:13), the covenant-cursed people receive its opposite — bitter, poisonous sustenance. Revelation 8:11 (the star Wormwood poisoning the waters) draws on this prophetic tradition.</p>",
    "16": "<p>'I will scatter them among nations that neither they nor their ancestors have known; and I will pursue them with the sword until I have consumed them' — the scattering among unknown nations intensifies the covenant-curse of Deuteronomy 28:36,64 ('the LORD will drive you and the king you set over you to a nation unknown to you or your fathers'). The 'unknown nations' are specifically non-Israel's covenant context: no temple, no land, no ancestral heritage, no community of Torah-observance. The sword-pursuit until consumption describes the sustained campaign: the exile will not be a brief diplomatic deportation but a comprehensive destruction.</p>",
    "17": "<p>'Consider this carefully; summon the professional mourning women to come; send for the most skilled among them to come' — professional mourners (<em>hamĕqônenôt</em>, the wailing women; <em>hahăkāmôt</em>, the skilled ones) were an institutionalized profession in the ancient Near East. In Israel, Egypt, and Mesopotamia, trained women were employed to amplify the communal grief at funerals through rhythmic wailing, composing and performing dirges (<em>qînôt</em>). Their professional skill was the ability to generate and sustain grief rituals that helped communities process collective loss. Jeremiah summons them because the coming loss will be too great for amateur lamentation.</p>",
    "18": "<p>'Let them come quickly and raise a lament over us, so that our eyes may stream with tears and our eyelids overflow with weeping' — the description of extreme grief — tears streaming from the eyes and overflowing from the eyelids — is the physiological language of Lamentations 1:16 ('my eye, my eye overflows with water'). The weeping is communal ('over us') — the professional mourners lead the community's grief rather than performing it on behalf of passive bystanders. In the ANE mourning context, the external wailing of the professionals was understood to draw out and legitimize the internal grief of the bereaved community.</p>",
    "19": "<p>'For a cry of wailing is heard from Zion: We are devastated! We are utterly disgraced — because we have had to leave the land, because our homes have been torn down' — the Zion lament anticipated in prophetic vision. The two causes of shame given — leaving the land (<em>kî ʿāzabnû ʾet-hāʾāreṣ</em>) and destroyed homes (<em>kî hišlîkû miškĕnôtênû</em>) — capture the two dimensions of the exile disaster: territorial displacement and household destruction. The land was the gift of the covenant; the home was the social unit of covenant practice. Both were lost simultaneously in the Babylonian deportation.</p>",
    "20": "<p>'Now, women, hear the word of the LORD; receive the word from his mouth. Teach your daughters to mourn; teach one another this dirge' — the address to women connects the professional mourning of vv. 17-18 to the generational transmission of communal grief practices. Just as the queen of heaven worship was transmitted from mothers to daughters (7:18), the mourning for the covenant's collapse must also be transmitted in the female sphere. The dirge to be taught is not merely a cultural grief expression but a covenant testimony: this is what happens when YHWH's people abandon the covenant.</p>",
    "21": "<p>'For death has climbed through our windows and entered our palaces, cutting down children in the streets and young men in the public squares' — the personification of death as an invader who enters through windows is found in Canaanite-Ugaritic mythology, where Mot (Death) is described as entering through windows. The specific targeting of children in the streets and young men in the squares (<em>ʾăpiqîm</em>, also translated as playgrounds/public squares) describes the urban massacre: the most visible and unprotected members of the community are killed first. The image appears in Lamentations 2:21 as fulfilled historical narrative.</p>",
    "22": "<p>'Human corpses will fall like manure on the open field, like grain stalks left behind by the reaper, with no one to gather them up' — the two comparison images are both agricultural: manure (the waste product of agriculture, abundant but valueless) and abandoned grain stalks (the reaper's leftovers). Both images describe bodies treated as refuse rather than as persons deserving burial rites. The 'no one to gather them up' (<em>wĕʾên mĕʾassēp</em>) is the denial of the harvesting function — the bodies lie in the field unrecovered, as if the community itself has ceased to function as a community.</p>",
    "23": "<p>'Let not the wise boast in their wisdom, nor the mighty in their strength, nor the rich in their wealth' — the three boasting prohibitions cover the standard ANE triads of human achievement: wisdom (the scribal class), strength (the warrior class), and wealth (the merchant class). Each was a form of social power that provided security in the human sphere. In the context of Jeremiah's time, these were also the three grounds on which the Jerusalem establishment justified its confidence in survival: they had wise advisors, a military, and economic resources. The oracle strips each ground of confidence by subordinating it to covenant knowledge.</p>",
    "24": "<p>'But let him who boasts boast in this: that he understands and knows me — that I am the LORD who exercises steadfast love, justice, and righteousness in the earth' — the three divine character qualities (<em>ḥesed</em>, <em>mišpāṭ</em>, <em>ṣĕdāqāh</em>) that YHWH declares he delights in are the exact covenant qualities that Israel's prophets consistently accuse the people of lacking. <em>Ḥesed</em> (steadfast love/covenant loyalty), <em>mišpāṭ</em> (justice), and <em>ṣĕdāqāh</em> (righteousness) are the Hosea 6:6, Amos 5:24, and Micah 6:8 triad. Paul quotes the verse's first half in 1 Corinthians 1:31 and 2 Corinthians 10:17, applying it to the cross as the proper ground of Christian boasting.</p>",
    "25": "<p>'The days are coming, declares the LORD, when I will punish all who are only outwardly circumcised' — the 'circumcised in foreskin' (<em>kol-mûl bĕʿorlāh</em>) but uncircumcised in heart extends the judgment beyond Israel to the surrounding nations. The passage (vv. 25-26) is unusual: it places Judah in the same category as Egypt, Edom, Ammon, Moab, and the desert peoples who practice circumcision as a custom but not as a covenant sign. Paul's argument in Romans 2:25-29 and Galatians 5:6 builds directly on this prophetic tradition: physical circumcision without covenant faithfulness is equivalent to non-circumcision.</p>",
    "26": "<p>'Egypt, Judah, Edom, Ammon, Moab, and all who live in the wilderness and clip the hair at their temples — for all these nations are physically uncircumcised, and all the house of Israel is uncircumcised in heart' — the nations listed (except possibly the desert peoples) practiced various forms of circumcision. Egypt circumcised as a coming-of-age rite; several Semitic peoples practiced it as a pre-marriage rite. The point is that circumcision as a physical practice was not distinctively Israelite — what was distinctive was its function as the covenant sign. Israel has reduced the covenant sign to the level of a pagan custom by maintaining the physical rite while ignoring the covenant commitment it represents. Deuteronomy 10:16 and 30:6 issued the same corrective.</p>",
  },
}

def main():
    existing = load_comm('mkt-context', 'jeremiah')
    merge_comm(existing, JER)
    save_comm('mkt-context', 'jeremiah', existing)
    il = json.loads((ROOT / 'data/interlinear/jeremiah.json').read_text())
    out = json.loads((ROOT / 'data/commentary/mkt-context/jeremiah.json').read_text())
    all_ok = True
    for ch in range(7, 10):
        ck = str(ch)
        missing = [v for v in il.get(ck, {}) if v not in out.get(ck, {})]
        if missing:
            print(f'  ch {ch} MISSING: {missing}')
            all_ok = False
        else:
            print(f'  ch {ch}: OK ({len(il.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present ✓')

if __name__ == '__main__':
    main()
